PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(SUM(?numRaces) AS ?total) WHERE {
  {
    SELECT ?season WHERE {
      ?season wdt:P31 wd:Q171879 ; wdt:P1346 wd:Q9671 ; wdt:P585 ?time .
    }
    ORDER BY ASC(?time)
    LIMIT 1
  } UNION {
    SELECT ?season WHERE {
      ?season wdt:P31 wd:Q171879 ; wdt:P1346 wd:Q9671 ; wdt:P585 ?time .
    }
    ORDER BY DESC(?time)
    LIMIT 1
  }
  ?season wdt:P1113 ?numRaces .
}

